"use client"

export function EditorialProductGrid() {
  return <div className="grid gap-px bg-white/10 lg:grid-cols-3"><article className="bg-background p-8 lg:col-span-2">Editorial product surface</article><aside className="bg-background p-8">Filter rail</aside></div>
}

export function SpatialGallery() {
  return <section className="grid min-h-[640px] grid-cols-12 gap-3"><div className="col-span-8 row-span-2 bg-zinc-900"/><div className="col-span-4 bg-red-950/30"/><div className="col-span-4 border border-white/10"/></section>
}

export function ProductDetail() {
  return <main className="grid gap-8 lg:grid-cols-[1.35fr_.65fr]"><section>Preview and files</section><aside>Install manifest</aside></main>
}

.wpx-reveal { animation: wpx-reveal 240ms cubic-bezier(.22,1,.36,1) both; }
@keyframes wpx-reveal { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: none; } }
@media (prefers-reduced-motion: reduce) { .wpx-reveal { animation: none; } }

"use client"

export function ImportWorkbench() {
  return <section className="grid gap-6 lg:grid-cols-[.7fr_1.3fr]"><aside>Source controls</aside><div>Normalized preview</div></section>
}

export function ReleaseConsole() {
  return <section className="grid gap-px bg-white/10 md:grid-cols-4"><div className="bg-background p-6">Plan</div><div className="bg-background p-6">Changes</div><div className="bg-background p-6">Validation</div><div className="bg-background p-6">Release</div></section>
}

export function PricingNarrative() {
  return <section className="grid gap-8 border-y border-white/10 py-16 lg:grid-cols-[.8fr_1.2fr]"><h2 className="font-display text-6xl">Choose by operating model.</h2><div className="divide-y divide-white/10">Free / Commercial / Enterprise</div></section>
}

export function CreatorProfile() {
  return <aside className="border border-white/10 p-6"><p className="font-mono text-xs uppercase tracking-[.2em] text-red-400">Verified creator</p><h3 className="mt-8 font-display text-4xl">WhisperX Studio</h3></aside>
}
